\begin{tikzpicture}[scale=1.5]
  % Square
  \fill[blue!20] (-1.5, -1.5) rectangle (1.5, 1.5);
  \draw[very thick, black] (-1.5, -1.5) rectangle (1.5, 1.5);

  % Vertical line of symmetry
  \draw[very thick, dashed, red] (0, -2) -- (0, 2);
  \node[red, font=\footnotesize, fill=white, inner sep=2pt, rotate=90] at (0.4, 0) {Line of Symmetry};

  % Label
  \node[below=0.6cm, font=\large, fill=white, inner sep=2pt] at (0, -2) {Square with 1 line of symmetry};
\end{tikzpicture}
